window.marked={parse:function(s){function e(t){return String(t||"").replace(/[&<>"']/g,function(c){return{"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[c]})}function inl(t){return e(t).replace(/\[([^\]]*)\]\((tcw:\/\/[^)\s]+)\)/g,function(m,txt,url){return'<a href="'+url+'">'+txt+"</a>"})}var out=[],list=null;String(s||"").split(/\r?\n/).forEach(function(line){var h=line.match(/^(#{1,3})\s+(.*)$/),li=line.match(/^[-*]\s+(.*)$/);if(h){if(list){out.push("</ul>");list=null}out.push("<h"+h[1].length+">"+inl(h[2])+"</h"+h[1].length+">")}else if(li){if(!list){out.push("<ul>");list=true}out.push("<li>"+inl(li[1])+"</li>")}else if(line.trim()){if(list){out.push("</ul>");list=null}out.push("<p>"+inl(line)+"</p>")}else if(list){out.push("</ul>");list=null}});if(list)out.push("</ul>");return out.join("")}};
